// Re-assert the two run-specific forall ensures so z3 picks up the
// triggers in the proof context. The originals come from the ensures
// of run 1 and run 2 but use disjoint triggers
// (`post1_self_.page_is_mapped(p)` vs `post2_self_.page_is_mapped(p)`),
// so z3 never instantiates them at the same `p`.
assert(forall|p: PagePtr|
    #![trigger post1_self_.page_is_mapped(p)]
    #![trigger post1_self_.page_mappings(p)]
    post1_self_.page_is_mapped(p) && p != target_ptr ==>
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_is_mapped(p)]
    #![trigger post2_self_.page_mappings(p)]
    post2_self_.page_is_mapped(p) && p != target_ptr ==>
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));

// Re-assert the `page_is_mapped <==> pre_self_.page_is_mapped` ensures
// for both runs so the post1 / post2 / pre triple of beliefs about
// `page_is_mapped(p)` and the mapped-page sets all line up.
assert(forall|p: PagePtr| #![auto]
    post1_self_.page_is_mapped(p) <==> pre_self_.page_is_mapped(p));
assert(forall|p: PagePtr| #![auto]
    post2_self_.page_is_mapped(p) <==> pre_self_.page_is_mapped(p));

// Push the abstract-view ensures (`post.X() =~= pre.X()` for each ghost
// set) through transitivity to bridge post1's view to post2's view.
assert(post1_self_.allocated_pages_4k@ =~= post2_self_.allocated_pages_4k@);
assert(post1_self_.allocated_pages_2m@ =~= post2_self_.allocated_pages_2m@);
assert(post1_self_.allocated_pages_1g@ =~= post2_self_.allocated_pages_1g@);
assert(post1_self_.mapped_pages_4k@ =~= post2_self_.mapped_pages_4k@);
assert(post1_self_.mapped_pages_2m@ =~= post2_self_.mapped_pages_2m@);
assert(post1_self_.mapped_pages_1g@ =~= post2_self_.mapped_pages_1g@);

// Lift the `container_map_4k` ensures (dom equality with pre, plus
// `get_container_owned_pages(c) =~= pre.get_container_owned_pages(c)`
// for `c` in the dom) into Map extensional equality across post1 and
// post2.
assert(post1_self_.container_map_4k@.dom() =~= post2_self_.container_map_4k@.dom());
assert forall|c: ContainerPtr|
    post1_self_.container_map_4k@.dom().contains(c) implies
        post1_self_.container_map_4k@[c] == post2_self_.container_map_4k@[c]
by {
    assert(post2_self_.container_map_4k@.dom().contains(c));
    assert(post1_self_.get_container_owned_pages(c)
        =~= pre_self_.get_container_owned_pages(c));
    assert(post2_self_.get_container_owned_pages(c)
        =~= pre_self_.get_container_owned_pages(c));
}
assert(post1_self_.container_map_4k@ =~= post2_self_.container_map_4k@);
